import { useRef } from 'react';
import ReactECharts from 'echarts-for-react';
import * as echarts from 'echarts';

import { cn } from '../utils/cn';
import { Skeleton } from '../skeleton/Skeleton';
import { guidewheelChartTheme } from './chart-theme';

const THEME_NAME = 'guidewheel';

let themeRegistered = false;

function registerTheme() {
  if (!themeRegistered) {
    echarts.registerTheme(THEME_NAME, guidewheelChartTheme);
    themeRegistered = true;
  }
}

type HChartProps = {
  option: echarts.EChartsOption;
  height?: number | string;
  isLoading?: boolean;
  className?: string;
  onEvents?: Record<string, (params: any) => void>;
};

/**
 * Generic ECharts wrapper for line, area, column, bar, and pie charts.
 *
 * Registers the Guidewheel theme on first render and shows a Skeleton
 * overlay while `isLoading` is true.
 */
function HChart({
  option,
  height = 300,
  isLoading = false,
  className,
  onEvents,
}: HChartProps) {
  registerTheme();

  const chartRef = useRef<ReactECharts>(null);

  return (
    <div data-slot="chart" className={cn('relative w-full', className)}>
      {isLoading && (
        <Skeleton
          className="absolute inset-0 z-10 rounded-md"
          style={{ height: typeof height === 'number' ? height : undefined }}
        />
      )}
      <ReactECharts
        ref={chartRef}
        option={option}
        theme={THEME_NAME}
        notMerge
        style={{ height, width: '100%' }}
        onEvents={onEvents}
      />
    </div>
  );
}

export { HChart };
export type { HChartProps };
